+export interface RvfaHeader {
+  magic: string;
+  version: number;
+  name: string;
+  appVersion: string;
+  arch: string;
+  platform: string;
+  profile: 'cloud' | 'hybrid' | 'offline';
+  created: string;
+  sections: RvfaSection[];
+  boot: RvfaBootConfig;
+  models: RvfaModelConfig;
+  capabilities: string[];
