+  async runNative(options: RunOptions): Promise<RunResult> {
+    const workDir = join(tmpdir(), `rvfa-${this.header.name}-${Date.now()}`);
+    try {
+      await mkdir(workDir, { recursive: true });
+
+      const ruflo = tryExtract(this.reader, 'ruflo');
