+      const decipher = createDecipheriv('aes-256-gcm', key, iv);
+      decipher.setAuthTag(tag);
+      const dec = Buffer.concat([decipher.update(ciphertext), decipher.final()]);
+      return JSON.parse(dec.toString('utf-8'));
+    } catch {
+      return null;
+    }
+  }
+}

