+    assert.equal(reader.extractSection('verify').toString(), 'v');
+  });
+
+  it('throws when extracting a nonexistent section', () => {
+    assert.throws(
+      () => RvfaReader.fromBuffer(validBuf).extractSection('nonexistent'),
+      /not found/,
+    );
+  });
+});
